<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body {font-family: Arial, sans-serif; margin: 20px;}
  table {border-collapse: collapse; user-select: none;}
  th, td {border: 1px solid #999; padding: 0; width: 80px; height: 24px; text-align: center;}
  th {background:#eee;}
  input {width: 100%; height: 100%; box-sizing: border-box; border:none; padding:0 2px; font-size:14px;}
  input:focus {outline:2px solid #6cf;}
  #controls {margin-top:10px;}
  #csv {width:100%; height:150px; margin-top:5px;}
</style>
</head>
<body>
<table id="sheet">
  <thead>
    <tr>
      <th></th>
      <th>A</th><th>B</th><th>C</th><th>D</th><th>E</th><th>F</th><th>G</th><th>H</th><th>I</th><th>J</th>
    </tr>
  </thead>
  <tbody>
    <!-- rows generated by script -->
  </tbody>
</table>

<div id="controls">
  <button id="export">Export CSV</button><br>
  <textarea id="csv" placeholder="CSV output will appear here"></textarea>
</div>

<script>
(() => {
  const COLS = ['A','B','C','D','E','F','G','H','I','J'];
  const ROWS = 10;
  const cells = {}; // id -> {raw, display}
  const cache = {}; // evaluation cache

  // create table rows
  const tbody = document.querySelector('#sheet tbody');
  for(let r=1;r<=ROWS;r++){
    const tr=document.createElement('tr');
    const th=document.createElement('th');
    th.textContent=r;
    tr.appendChild(th);
    for(let c=0;c<COLS.length;c++){
      const col=COLS[c];
      const id=`${col}${r}`;
      const td=document.createElement('td');
      const inp=document.createElement('input');
      inp.id=`cell-${id}`;
      inp.dataset.id=id;
      td.appendChild(inp);
      tr.appendChild(td);
      cells[id]={raw:'',display:''};
    }
    tbody.appendChild(tr);
  }

  // helpers
  const isLetter = ch=>/[A-J]/.test(ch);
  const isDigit = ch=>/[0-9]/.test(ch);
  const isCellRef = str=>/^[A-J](?:[1-9]|10)$/.test(str);

  // evaluation
  function evalAll(){
    Object.keys(cache).forEach(k=>delete cache[k]);
    for(const id in cells){
      const val = evalNumeric(id, []);
      // set display
      const raw = cells[id].raw;
      if(raw.startsWith('=')){
        cells[id].display = (typeof val==='number')?String(val):val;
      }else{
        cells[id].display = raw;
      }
    }
    updateUI();
  }

  function evalNumeric(id, stack){
    if(cache.hasOwnProperty(id)) return cache[id];
    if(stack.includes(id)){
      // cycle detected
      stack.forEach(cellId=>cache[cellId]='#CYCLE');
      return '#CYCLE';
    }
    stack.push(id);
    const raw = cells[id].raw;
    let result;
    if(raw.startsWith('=')){
      try{
        result = evaluateFormula(raw.slice(1), stack);
        if(typeof result!=='number' || !isFinite(result)) result = '#ERR';
      }catch(e){
        result = '#ERR';
      }
    }else{
      const trimmed = raw.trim();
      if(trimmed==='') result = 0;
      else if(!isNaN(trimmed)) result = parseFloat(trimmed);
      else result = '#ERR';
    }
    stack.pop();
    cache[id]=result;
    return result;
  }

  function evaluateFormula(expr, stack){
    let pos=0;
    const len=expr.length;
    const skipSpaces=()=>{while(pos<len && /\s/.test(expr[pos]))pos++;};
    const peek=()=>expr[pos];
    const get=()=>expr[pos++];
    const parseNumber=()=>{
      skipSpaces();
      let start=pos;
      while(pos<len && (isDigit(expr[pos])||expr[pos]==='.' ))pos++;
      const numStr=expr.slice(start,pos);
      if(numStr===''||isNaN(numStr))throw new Error('Invalid number');
      return parseFloat(numStr);
    };
    const parseCell=()=>{
      skipSpaces();
      if(!isLetter(peek()))throw new Error('Invalid cell');
      const col=get();
      let row='';
      while(pos<len && isDigit(peek())) row+=get();
      const ref=`${col}${row}`;
      if(!isCellRef(ref))throw new Error('Bad reference');
      const val=evalNumeric(ref, stack);
      if(typeof val!=='number')throw new Error('Ref error');
      return val;
    };
    const parseFactor=()=>{
      skipSpaces();
      const ch=peek();
      if(ch=== '('){
        get(); const v=parseExpression(); skipSpaces(); if(get()!==')')throw new Error('Missing )'); return v;
      }else if(isDigit(ch)||ch==='.'){
        return parseNumber();
      }else if(isLetter(ch)){
        return parseCell();
      }else{
        throw new Error('Unexpected token');
      }
    };
    const parseTerm=()=>{
      let v=parseFactor();
      while(true){
        skipSpaces();
        const ch=peek();
        if(ch==='*' || ch==='/'){
          get();
          const rhs=parseFactor();
          if(ch==='*') v=v*rhs; else v=v/rhs;
        }else break;
      }
      return v;
    };
    const parseExpression=()=>{
      let v=parseTerm();
      while(true){
        skipSpaces();
        const ch=peek();
        if(ch==='+'||ch==='-'){
          get();
          const rhs=parseTerm();
          if(ch==='+') v=v+rhs; else v=v-rhs;
        }else break;
      }
      return v;
    };
    const result=parseExpression();
    skipSpaces();
    if(pos!==len)throw new Error('Trailing chars');
    return result;
  }

  // UI updates
  function updateUI(){
    for(const id in cells){
      const inp=document.getElementById(`cell-${id}`);
      if(document.activeElement!==inp){
        inp.value=cells[id].display;
      }
    }
  }

  // event handling
  function commitCell(inp){
    const id=inp.dataset.id;
    const newRaw=inp.value;
    cells[id].raw=newRaw;
    evalAll();
  }

  document.querySelectorAll('input').forEach(inp=>{
    inp.addEventListener('focus',e=>{
      const id=e.target.dataset.id;
      e.target.value=cells[id].raw;
    });
    inp.addEventListener('blur',e=>{
      commitCell(e.target);
    });
    inp.addEventListener('keydown',e=>{
      if(e.key==='Enter'){
        e.target.blur();
      }
    });
  });

  // Export CSV
  document.getElementById('export').addEventListener('click',()=>{
    const rows=[];
    for(let r=1;r<=ROWS;r++){
      const cols=[];
      for(let c=0;c<COLS.length;c++){
        const id=`${COLS[c]}${r}`;
        cols.push(cells[id].display);
      }
      rows.push(cols.join(','));
    }
    document.getElementById('csv').value=rows.join('\n');
  });

  // expose API
  window.sheet = {
    set(id, txt){
      if(cells[id]){
        cells[id].raw=txt;
        evalAll();
      }
    },
    get(id){
      return cells[id]?cells[id].display:'';
    },
    raw(id){
      return cells[id]?cells[id].raw:'';
    }
  };

  // initial evaluation
  evalAll();
})();
</script>
</body>
</html>
